import React, { useState, useEffect } from "react";
import {
  Box, Card, CardContent, Typography, Grid,
  Table, TableHead, TableRow, TableCell, TableBody,
  Button
} from "@mui/material";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [activeSection, setActiveSection] = useState("overview");
  const [details, setDetails] = useState([]);
  const navigate = useNavigate();

  const fetchOverview = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/admin/overview");
      setOverview(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchDetails = async (section) => {
    setActiveSection(section);
    if (section === "overview") return fetchOverview();

    let url = "";
    switch (section) {
      case "users": url = "http://localhost:5000/api/admin/users"; break;
      case "captains": url = "http://localhost:5000/api/admin/captains"; break;
      case "pendingCaptains": url = "http://localhost:5000/api/admin/pending-captains"; break;
      case "rides": url = "http://localhost:5000/api/admin/rides"; break;
      default: return;
    }

    try {
      const res = await axios.get(url);
      setDetails(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const handleCaptainAction = async (id, action) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/captain/${id}/${action}`);
      fetchDetails("pendingCaptains");
      fetchOverview();
    } catch (err) {
      console.error(err);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    navigate("/admin-login");
  };

  useEffect(() => { fetchOverview(); }, []);

  return (
    <Box p={4}>
      {/* Header */}
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Typography variant="h4">Admin Dashboard</Typography>
        <Button variant="contained" color="error" onClick={handleLogout}>
          Logout
        </Button>
      </Box>

      {/* Top Cards */}
      <Grid container spacing={2} mb={4}>
        {[
          { key: "overview", label: "Overview" },
          { key: "users", label: "Users" },
          { key: "captains", label: "Captains" },
          { key: "pendingCaptains", label: "Pending Captains" },
          { key: "rides", label: "Rides" }
        ].map(item => (
          <Grid item xs={12} sm={6} md={2} key={item.key}>
            <Card onClick={() => fetchDetails(item.key)} sx={{ cursor: "pointer" }}>
              <CardContent>
                <Typography variant="h6">{item.label}</Typography>
                {item.key === "overview" && (
                  <>
                    <Typography>Users: {overview.usersCount || 0}</Typography>
                    <Typography>Riders: {overview.ridersCount || 0}</Typography>
                    <Typography>Captains: {overview.captainsCount || 0}</Typography>
                    <Typography>Pending: {overview.pendingCaptainsCount || 0}</Typography>
                    <Typography>Rides: {overview.ridesCount || 0}</Typography>
                  </>
                )}
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {/* Tables */}
      {activeSection !== "overview" && (
        <Table>
          <TableHead>
            <TableRow>
              {activeSection === "rides" ? (
                <>
                  <TableCell>Rider</TableCell>
                  <TableCell>Captain</TableCell>
                  <TableCell>Pickup</TableCell>
                  <TableCell>Drop</TableCell>
                  <TableCell>Fare</TableCell>
                  <TableCell>Status</TableCell>
                  <TableCell>Date</TableCell>
                  <TableCell>Actions</TableCell>
                </>
              ) : (
                <>
                  {details[0] && Object.keys(details[0]).map(key => (
                    <TableCell key={key}>{key}</TableCell>
                  ))}
                  {activeSection === "pendingCaptains" && <TableCell>Actions</TableCell>}
                </>
              )}
            </TableRow>
          </TableHead>
          <TableBody>
            {details.map((item, idx) => (
              <TableRow key={idx}>
                {activeSection === "rides" ? (
                  <>
                    <TableCell>{item.riderId?.fullName || "N/A"}</TableCell>
                    <TableCell>{item.captainId?.fullName || "Unassigned"}</TableCell>
                    <TableCell>{item.origin?.address || "N/A"}</TableCell>
                    <TableCell>{item.destination?.address || "N/A"}</TableCell>
                    <TableCell>₹{item.fare || 0}</TableCell>
                    <TableCell>{item.status}</TableCell>
                    <TableCell>{new Date(item.createdAt).toLocaleString()}</TableCell>
                    <TableCell>
                      <Button size="small" variant="outlined">View</Button>
                    </TableCell>
                  </>
                ) : (
                  <>
                    {Object.keys(item).map(key => (
                      <TableCell key={key}>
                        {typeof item[key] === "object" ? JSON.stringify(item[key]) : item[key]}
                      </TableCell>
                    ))}
                    {activeSection === "pendingCaptains" && (
                      <TableCell>
                        <Button
                          color="success"
                          onClick={() => handleCaptainAction(item._id, "approve")}
                          sx={{ mr: 1 }}
                        >
                          Approve
                        </Button>
                        <Button
                          color="error"
                          onClick={() => handleCaptainAction(item._id, "reject")}
                        >
                          Reject
                        </Button>
                      </TableCell>
                    )}
                  </>
                )}
              </TableRow>
            ))}
            {!details.length && (
              <TableRow>
                <TableCell colSpan={10} align="center">No records found.</TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      )}
    </Box>
  );
}
